import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "When should you refinance your mortgage?", a: "Refinancing may make sense when the monthly savings, term improvement, or cash-out benefit outweighs closing costs and long-term interest tradeoffs." },
  { q: "How do you calculate the break-even point on a refinance?", a: "Divide closing costs by monthly savings. The result is the number of months needed to recover the refinance cost." },
  { q: "What are typical refinance closing costs?", a: "Closing costs often range from 2% to 6% of the loan amount, depending on lender fees, points, appraisal, title, and taxes." },
  { q: "What is a cash-out refinance?", a: "A cash-out refinance replaces your existing loan with a larger new loan and gives you the difference in cash." },
  { q: "How does refinancing affect your credit score?", a: "Refinancing can affect credit through hard inquiries, a new account, account age changes, and payment history on the new loan." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function payment(principal: number, apr: number, months: number) { const r = apr / 100 / 12; return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months)); }

export default function RefinanceCalculator() {
  useCurrencyVersion();
  const [balance, setBalance] = useState(250000);
  const [remainingTerm, setRemainingTerm] = useState(300);
  const [currentRate, setCurrentRate] = useState(7);
  const [newRate, setNewRate] = useState(5.5);
  const [closingCosts, setClosingCosts] = useState(5000);
  const result = useMemo(() => { const current = payment(balance, currentRate, remainingTerm); const next = payment(balance, newRate, remainingTerm); const savings = current - next; const breakEven = savings > 0 ? closingCosts / savings : 0; const lifetime = savings * remainingTerm - closingCosts; return { current, next, savings, breakEven, lifetime }; }, [balance, remainingTerm, currentRate, newRate, closingCosts]);
  const rates = [5, 5.5, 6, 6.5];
  return (
    <>
      <SEOHead title="Free Refinance Calculator Online - Calculate Refinance Savings and Break-Even Instantly | CalcHive" description="Free online refinance calculator. Calculate monthly savings, break-even point and total refinance savings for any loan balance, rate change and closing costs instantly. 100% free, no signup required." canonical="/refinance-calculator" keywords="free refinance calculator, mortgage refinance calculator free online, should I refinance calculator free, refinance break even calculator free, home refinance savings calculator free" category="Financial Calculators" breadcrumbName="Free Refinance Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Refinance Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate refinance monthly savings, break-even point, and lifetime savings after closing costs.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Current loan balance</label><input type="number" value={balance} onChange={(e) => setBalance(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Remaining term months</label><input type="number" value={remainingTerm} onChange={(e) => setRemainingTerm(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Current rate (%)</label><input type="number" value={currentRate} onChange={(e) => setCurrentRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">New rate (%)</label><input type="number" value={newRate} onChange={(e) => setNewRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Closing costs</label><input type="number" value={closingCosts} onChange={(e) => setClosingCosts(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Savings</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.savings)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">New payment</p><p className="text-lg font-extrabold text-foreground">{money(result.next)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Break-even</p><p className="text-lg font-extrabold text-foreground">{result.breakEven.toFixed(1)} mo</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Lifetime savings</p><p className="text-lg font-extrabold text-foreground">{money(result.lifetime)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate If Refinancing Saves You Money for Free</h2><p className="text-muted-foreground leading-relaxed">Compare your current monthly payment to the new payment, then subtract closing costs from total savings.</p><h2 className="text-2xl font-bold text-foreground">How to Find Your Refinance Break-Even Point</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Refinance Savings on $250,000 Balance - Current Rate 7%</caption><thead className="bg-muted/60"><tr>{["New Rate", "New Monthly Payment", "Monthly Savings", "Closing Costs Recovery", "Total Savings over 5yr"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rates.map((r) => { const oldPay = payment(250000, 7, 300); const newPay = payment(250000, r, 300); const save = oldPay - newPay; return <tr key={r}><td className="py-2.5 px-3 font-semibold">{r}%</td><td className="py-2.5 px-3">{money(newPay)}</td><td className="py-2.5 px-3">{money(save)}</td><td className="py-2.5 px-3">{save > 0 ? `${(5000 / save).toFixed(1)} mo` : "N/A"}</td><td className="py-2.5 px-3">{money(save * 60 - 5000)}</td></tr>; })}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Mortgage Refinance Calculator for Homeowners</h2><p className="text-muted-foreground leading-relaxed">Use this refinance calculator to compare rate offers, closing costs, and how long you plan to keep the loan.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/refinance-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


